{
  "Query" :"let events = DeviceTvmSecureConfigurationAssessment | where ConfigurationSubcategory == 'Attack Surface Reduction' | summarize max(Timestamp) by DeviceName | extend Timestamp = max_Timestamp | join kind=rightouter (DeviceTvmSecureConfigurationAssessment | where ConfigurationId == 'scid-2000' | where IsCompliant == 1 and IsApplicable == 1 | summarize arg_max(Timestamp, *) by DeviceName) on $left.DeviceName == $right.DeviceName | project Timestamp=max_Timestamp, DeviceName; events | join kind=leftouter (DeviceTvmSecureConfigurationAssessment | where ConfigurationSubcategory == 'Attack Surface Reduction') on $left.DeviceName == $right.DeviceName and $left.Timestamp == $right.Timestamp | extend RuleState = case(Context contains 'Audit','Audit',Context contains 'Block','Block',Context contains 'Off','Off','Empty') | extend RuleStates = pack('RuleState', RuleState, 'ConfigurationId', ConfigurationId, 'IsCompliant',IsCompliant,'IsApplicable',IsApplicable,'IsExpectedUserImpact', IsExpectedUserImpact) | summarize make_list(RuleStates) by DeviceName | join kind=leftouter events on DeviceName | project DeviceName,list_RuleStates,Timestamp | project-rename event_timestamp = Timestamp"
}
